// Transforma payload do Manychat → formato esperado pelo CRM (/api/public/leads)
// Manychat envia campos como: first_name, last_name, email, phone, ig_username,
// ad_name, channel (instagram/facebook/whatsapp), text (última mensagem), etc.

const body = $('Webhook (Manychat)').first().json.body ?? $('Webhook (Manychat)').first().json;
const config = $('Config (edite aqui)').first().json;

// Constrói o nome — Manychat geralmente separa first/last
const firstName = body.first_name ?? body.firstName ?? '';
const lastName  = body.last_name  ?? body.lastName  ?? '';
const fullName  = (body.full_name ?? body.name ?? `${firstName} ${lastName}`).trim() || 'Lead Manychat';

// Mapeia o canal do Manychat para o enum source do CRM
const channelMap = {
  instagram:        'INSTAGRAM',
  ig:               'INSTAGRAM',
  facebook:         'FACEBOOK',
  fb:               'FACEBOOK',
  messenger:        'FACEBOOK',
  whatsapp:         'WHATSAPP',
  wa:               'WHATSAPP',
};
const rawChannel = (body.channel ?? body.source ?? '').toLowerCase();
const source     = channelMap[rawChannel] ?? 'OUTRO';

return {
  json: {
    // Obrigatórios
    tenantSlug: config.tenantSlug,
    name:       fullName,

    // Recomendados
    email:   body.email   || null,
    phone:   body.phone   || body.whatsapp || null,
    company: body.company || null,
    source,

    // Contexto extra (vira nota)
    ad_name: body.ad_name ?? body.adset_name ?? null,
    form_id: body.form_id ?? null,
    message: body.last_input_text ?? body.text ?? body.message ?? null,

    // Atribuição
    utm_source:   body.utm_source   ?? 'manychat',
    utm_medium:   body.utm_medium   ?? rawChannel,
    utm_campaign: body.utm_campaign ?? body.ad_name ?? null,

    // Metadados (passa pro próximo nó, não vai pro CRM)
    _meta: {
      subscriber_id:      body.subscriber_id      ?? null,
      instagram_username: body.ig_username        ?? null,
      manychat_user_url:  body.user_url           ?? null,
    },
  },
};
